import React from 'react'

export default function item(props) {
  return (
        <tr>
            <th>{props.info.name}</th>
            <th>{props.info.price}</th>
            <th>{props.info.amount}</th>
            <th><button onClick={()=>{props.add(props.info.name)}}>+</button></th>
            <th><button onClick={()=>{props.remove(props.info.name)}} >-</button></th>
        </tr>
  )
}
